// la stabilità del driver video (GPU).
// =========================================================================

#define PI_S 3.14159265359
float tempo_val = 2.0;

// Funzioni Hash uniche per evitare conflitti di nomi
float hash_s(float x) { return fract(sin(x) * 897612.531); }
float hsh_s(float x) { return fract(sin(x * 237.234234) * 982734.1235); }
float rnd_s(float x, float mn, float mx) { return mn + floor((mx - mn) * hash_s(floor(x))); }

float nse_s(float x) {
    float y = floor(x);
    float f = fract(x);
    f = f * f * (3.0 - 2.0 * f);
    return mix(hash_s(y), hash_s(y + 1.0), f) - 0.5;
}

// Strumento: Campana FM
vec2 inst_bell(float t, float f) {
    float m = sin(t * f * 80.0) * exp(t * -50.0);
    float sig = sin(t * f * PI_S * 2.0 + m) * min(t * 800.0, 1.0) * exp(t * -5.0) * 0.25;
    return vec2(sig);
}

// Strumento: Vocale "A"
float voc_s(float t, float f, float formant) {
    float x = fract(t * f) / f;
    return (sin(x * 6.0 * formant) * 0.4 + sin(x * 12.0 * formant) + sin(x * 26.0 * formant) * 0.2) * min(x * 1000.0, 1.0) * exp(x * -200.0);
}

// Coro Swarm (Ridotto a 4 voci per performance)
vec2 inst_choir(float t, float f) {
    vec2 v = vec2(0.0);
    float formant = 300.0 * exp2(sin(t * 0.1));
    for(int i = 0; i < 4; ++i) {
        float h = float(i);
        float m = voc_s(t + h / 3.0, f + pow(2.01, (h - 8.0) * 0.2), formant);
        float pan = hash_s(h);
        v.x += m * pan;
        v.y += m * (1.0 - pan);
    }
    return v * 0.15;
}

// Strumento secondario (Armoniche)
vec2 inst_harm(float t, float f) {
    vec2 v = vec2(0.0);
    for(int i = 0; i < 4; ++i) {
        float h = float(i) * 2.0 + 1.0;
        float m = sin(t * f * 2.0 * PI_S * h) * (1.0 + nse_s(h * 41.0 + t * 10.0)) / h;
        float pan = hash_s(h);
        v.x += m * pan;
        v.y += m * (1.0 - pan);
    }
    return v * 0.2;
}

float penta_s(float x) {
    x /= 5.0;
    float y = floor(x);
    float fr = fract(x) * 5.0;
    return step(1.0, fr) * 2.0 + step(2.0, fr) * 3.0 + step(3.0, fr) * 2.0 + step(4.0, fr) * 2.0 + y * 12.0;
}

vec2 scene_choir(float time, float n) {
    vec2 v = inst_choir(time, 140.0 * pow(2.0, n / 12.0));
    v += inst_choir(-time, 140.0 * pow(2.0, n / 12.0 - 1.0));
    if(time > 64.0 / tempo_val) {
        v += inst_harm(time, 140.0 * 3.0 * pow(2.0, (n + 12.0) / 12.0)) * 0.1;
    }
    return v;
}

vec2 snare_s(float t) {
    if(t < 0.0) return vec2(0.0);
    t *= 3.0;
    float env = exp(t * -10.0) + exp(t * -1.0) * 0.07;
    return vec2(hsh_s(t), hsh_s(t + 0.1)) * env * 0.4;
}

vec2 echomix_s(float time) {
    vec2 v = vec2(0.0);
    float x = mod(time, 8.0 / tempo_val);
    v += vec2(0.5) * sin(pow(x, 0.9) * 300.0) * min(1.0, x * 200.0) * exp(x * -5.0);
    float rate = tempo_val * 2.0;
    if(time > 32.0 / tempo_val)
        v += inst_bell(fract(time * rate) / rate, 140.0 * 2.0 * pow(2.0, penta_s(rnd_s(time * rate, 0.0, 10.0)) / 12.0)) * 0.4;
    return v;
}

// Funzione principale adattata al tuo synthesizer.cpp
vec2 mainSound(in int samp, float time) {
    vec2 v = echomix_s(time);
    float x = mod(time, 32.0 / tempo_val);

    // Gestione dinamica del coro
    v += scene_choir(time, -5.0) * clamp(x * tempo_val * 0.5, 0.0, 1.0) * smoothstep(20.0, 15.0, x * tempo_val);

    if(time >= 30.0) { // Ridotto tempo di attivazione snare per test immediato
        v += snare_s(mod(time - 0.5, 1.0)) * 0.15;
    }

    // Mastering finale con limiter
    return clamp(v * 0.6, -1.0, 1.0);
}
